"use client";

import { useState } from "react";
import { Plane, ExternalLink, Loader2, DollarSign, Clock } from "lucide-react";
import type { DashboardFeatureProps } from "@/types";
import { searchFlights, type Flight } from "@/lib/services/mockFlights";

export default function Bookings({ room, onLocationChange }: DashboardFeatureProps) {
  const [origin, setOrigin] = useState("");
  const [destination, setDestination] = useState(room.destination || "");
  const [date, setDate] = useState("");

  // Flight Search State
  const [flights, setFlights] = useState<Flight[]>([]);
  const [loading, setLoading] = useState(false);
  const [hasSearched, setHasSearched] = useState(false);

  const handleSearch = async () => {
    if (!origin || !destination) return;
    setLoading(true);
    setHasSearched(true);
    try {
      const results = await searchFlights(origin, destination, date || "any");
      setFlights(results);
      onLocationChange(destination);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const googleFlightsUrl = `https://www.google.com/travel/flights?q=flights+from+${encodeURIComponent(origin)}+to+${encodeURIComponent(destination)}${date ? `+on+${date}` : ""}`;

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-2xl font-bold text-gray-900">Bookings & Flights</h2>
        <p className="text-gray-500 mt-1">Search estimates and book real flights</p>
      </div>

      {/* Search Form */}
      <div className="bg-white rounded-xl border p-6 space-y-4 shadow-sm">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">From</label>
            <input
              type="text"
              value={origin}
              onChange={(e) => setOrigin(e.target.value)}
              placeholder="Origin city"
              className="w-full px-4 py-2.5 border rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">To</label>
            <input
              type="text"
              value={destination}
              onChange={(e) => setDestination(e.target.value)}
              placeholder="Destination city"
              className="w-full px-4 py-2.5 border rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
            />
          </div>
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Date</label>
          <input
            type="date"
            value={date}
            onChange={(e) => setDate(e.target.value)}
            className="w-full px-4 py-2.5 border rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
          />
        </div>
        <button
          onClick={handleSearch}
          disabled={loading || !origin || !destination}
          className="w-full sm:w-auto px-6 py-2.5 bg-teal-600 hover:bg-teal-700 text-white font-medium rounded-lg flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
        >
          {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Plane className="w-4 h-4" />}
          Find Flights
        </button>
      </div>

      {/* Results Area */}
      {loading ? (
        <div className="flex justify-center py-12">
          <Loader2 className="w-8 h-8 text-teal-600 animate-spin" />
        </div>
      ) : hasSearched && flights.length > 0 ? (
        <div className="space-y-4">
          <h3 className="font-semibold text-gray-900">Estimated Prices</h3>
          <div className="grid gap-4">
            {flights.map((flight) => (
              <div key={flight.id} className="bg-white border rounded-xl p-4 flex flex-col sm:flex-row items-center justify-between gap-4 hover:shadow-md transition-shadow">
                <div className="flex items-center gap-4 w-full sm:w-auto">
                  <div className="w-12 h-12 bg-blue-50 rounded-full flex items-center justify-center">
                    <Plane className="w-5 h-5 text-blue-600" />
                  </div>
                  <div>
                    <h4 className="font-bold text-gray-900">{flight.airline}</h4>
                    <div className="flex items-center gap-2 text-sm text-gray-500">
                      <Clock className="w-3 h-3" />
                      {flight.departure} - {flight.arrival}
                    </div>
                  </div>
                </div>
                <div className="flex items-center justify-between w-full sm:w-auto gap-6">
                  <div className="text-right">
                    <span className="block text-2xl font-bold text-teal-600">${flight.price}</span>
                    <span className="text-xs text-gray-400">avg. per person</span>
                  </div>
                  <a
                    href={flight.bookingUrl}
                    target="_blank"
                    rel="noreferrer"
                    className="px-4 py-2 bg-gray-900 text-white text-sm font-medium rounded-lg hover:bg-gray-800 transition-colors"
                  >
                    Book
                  </a>
                </div>
              </div>
            ))}
          </div>
          <p className="text-xs text-center text-gray-400 mt-4">
            * Prices are estimates based on historical data. Click "Book" to see real-time pricing on Google Flights.
          </p>
        </div>
      ) : null}

      {/* External Links */}
      <div className="grid grid-cols-1 gap-4 pt-4 border-t">
        <a
          href={googleFlightsUrl}
          target="_blank"
          rel="noopener noreferrer"
          className="flex items-center justify-between p-4 bg-gray-50 rounded-lg hover:bg-gray-100 transition-colors"
        >
          <div className="flex items-center gap-3">
            <Plane className="w-5 h-5 text-gray-600" />
            <span className="font-medium text-gray-900">Open Google Flights</span>
          </div>
          <ExternalLink className="w-4 h-4 text-gray-400" />
        </a>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { Send, Loader2 } from "lucide-react";
import { createClient } from "@/lib/supabase/client";
import type { DashboardFeatureProps, ChatMessage } from "@/types";

export default function ChatRoom({ room, user }: DashboardFeatureProps) {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const supabase = createClient();

  // Load messages & subscribe to real-time updates
  useEffect(() => {
    const loadMessages = async () => {
      const { data } = await supabase
        .from("chat_messages")
        .select("*")
        .eq("room_id", room.id)
        .order("created_at", { ascending: true })
        .limit(100);

      if (data) setMessages(data);
    };

    loadMessages();

    const channel = supabase
      .channel(`room-${room.id}`)
      .on(
        "postgres_changes",
        {
          event: "INSERT",
          schema: "public",
          table: "chat_messages",
          filter: `room_id=eq.${room.id}`,
        },
        (payload) => {
          setMessages((prev) => [...prev, payload.new as ChatMessage]);
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [room.id]);

  // Auto-scroll
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const sendMessage = async () => {
    if (!input.trim()) return;
    const text = input.trim();
    setInput("");

    // AI message detection
    if (text.startsWith("/ai ") || text.startsWith("@ai ")) {
      const aiPrompt = text.replace(/^(\/ai\s|@ai\s)/, "");
      setLoading(true);

      // Insert user message
      await supabase.from("chat_messages").insert({
        room_id: room.id,
        user_id: user.id,
        user_name: user.name,
        message: text,
      });

      try {
        const res = await fetch("/api/ai/chat", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            message: aiPrompt,
            destination: room.destination,
          }),
        });
        const data = await res.json();

        // Insert AI response
        await supabase.from("chat_messages").insert({
          room_id: room.id,
          user_id: user.id,
          user_name: "Tripp AI ≡ƒñû",
          message: data.reply || "Sorry, I couldn't process that.",
        });
      } catch {
        await supabase.from("chat_messages").insert({
          room_id: room.id,
          user_id: user.id,
          user_name: "Tripp AI ≡ƒñû",
          message: "Sorry, I'm having trouble responding right now.",
        });
      } finally {
        setLoading(false);
      }
      return;
    }

    // Regular message
    await supabase.from("chat_messages").insert({
      room_id: room.id,
      user_id: user.id,
      user_name: user.name,
      message: text,
    });
  };

  return (
    <div className="flex flex-col h-[calc(100vh-10rem)]">
      <div className="mb-4">
        <h2 className="text-2xl font-bold text-gray-900">Chat Room</h2>
        <p className="text-gray-500 mt-1">
          Chat with your travel group. Type{" "}
          <code className="text-teal-600 bg-teal-50 px-1 rounded">
            /ai
          </code>{" "}
          to ask Tripp AI.
        </p>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto bg-white rounded-xl border p-4 space-y-3 mb-4">
        {messages.length === 0 && (
          <div className="text-center py-12 text-gray-400 text-sm">
            No messages yet. Start the conversation!
          </div>
        )}
        {messages.map((msg) => {
          const isOwn =
            msg.user_id === user.id && !msg.user_name.includes("AI");
          const isAI = msg.user_name.includes("AI");
          return (
            <div
              key={msg.id}
              className={`flex ${isOwn ? "justify-end" : "justify-start"}`}
            >
              <div
                className={`max-w-[75%] rounded-2xl px-4 py-2.5 ${
                  isAI
                    ? "bg-purple-50 border border-purple-200"
                    : isOwn
                      ? "bg-teal-500 text-white"
                      : "bg-gray-100"
                }`}
              >
                {!isOwn && (
                  <p
                    className={`text-xs font-medium mb-1 ${
                      isAI ? "text-purple-600" : "text-gray-500"
                    }`}
                  >
                    {msg.user_name}
                  </p>
                )}
                <p
                  className={`text-sm whitespace-pre-wrap ${
                    isOwn ? "text-white" : "text-gray-800"
                  }`}
                >
                  {msg.message}
                </p>
                <p
                  className={`text-xs mt-1 ${
                    isOwn ? "text-teal-100" : "text-gray-400"
                  }`}
                >
                  {new Date(msg.created_at).toLocaleTimeString([], {
                    hour: "2-digit",
                    minute: "2-digit",
                  })}
                </p>
              </div>
            </div>
          );
        })}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div className="flex gap-2">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Type a message... (use /ai for AI help)"
          className="flex-1 px-4 py-2.5 border rounded-xl focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none"
          onKeyDown={(e) =>
            e.key === "Enter" && !e.shiftKey && sendMessage()
          }
          disabled={loading}
        />
        <button
          onClick={sendMessage}
          disabled={!input.trim() || loading}
          className="px-4 py-2.5 bg-teal-600 hover:bg-teal-700 disabled:bg-gray-300 text-white rounded-xl transition-colors"
        >
          {loading ? (
            <Loader2 className="w-5 h-5 animate-spin" />
          ) : (
            <Send className="w-5 h-5" />
          )}
        </button>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { MapPin, Star, Loader2, Sparkles } from "lucide-react";
import type { DashboardFeatureProps, Restaurant } from "@/types";

export default function ExploringFood({
  room,
  onLocationChange,
}: DashboardFeatureProps) {
  const [destination, setDestination] = useState(room.destination || "");
  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const searchFood = async () => {
    if (!destination) return;
    setLoading(true);
    setError("");
    onLocationChange(destination);

    try {
      const res = await fetch("/api/ai/food", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ destination }),
      });
      const data = await res.json();
      if (data.error) throw new Error(data.error);
      setRestaurants(data.restaurants || []);
    } catch (err: any) {
      setError(err.message || "Failed to load recommendations");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-2xl font-bold text-gray-900">Exploring Food</h2>
        <p className="text-gray-500 mt-1">
          Discover the best local cuisine with AI
        </p>
      </div>

      <div className="bg-white rounded-xl border p-6">
        <div className="flex gap-3">
          <div className="relative flex-1">
            <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input
              type="text"
              value={destination}
              onChange={(e) => setDestination(e.target.value)}
              placeholder="Search by city..."
              className="w-full pl-10 pr-4 py-2.5 border rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none"
              onKeyDown={(e) => e.key === "Enter" && searchFood()}
            />
          </div>
          <button
            onClick={searchFood}
            disabled={!destination || loading}
            className="px-4 py-2.5 bg-teal-600 hover:bg-teal-700 disabled:bg-gray-300 text-white font-medium rounded-lg flex items-center gap-2 transition-colors"
          >
            {loading ? (
              <Loader2 className="w-4 h-4 animate-spin" />
            ) : (
              <Sparkles className="w-4 h-4" />
            )}
            Search
          </button>
        </div>
      </div>

      {error && (
        <div className="bg-red-50 border border-red-200 text-red-700 rounded-lg p-4 text-sm">
          {error}
        </div>
      )}

      {restaurants.length > 0 && (
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          {restaurants.map((r, i) => (
            <div
              key={i}
              className="bg-white rounded-xl border p-5 hover:shadow-md transition-shadow"
            >
              <div className="flex items-start justify-between mb-2">
                <div>
                  <h3 className="font-semibold text-gray-900">{r.name}</h3>
                  <p className="text-sm text-gray-500">{r.cuisine}</p>
                </div>
                <span className="text-sm font-medium text-gray-600">
                  {r.price_range}
                </span>
              </div>
              <p className="text-sm text-gray-600 mb-3">{r.description}</p>
              <div className="flex items-center gap-1">
                <Star className="w-4 h-4 text-amber-500 fill-amber-500" />
                <span className="text-sm font-medium text-gray-700">
                  {r.rating}
                </span>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import {
  Calendar,
  MapPin,
  Users,
  Loader2,
  Sparkles,
  Clock,
} from "lucide-react";
import type { DashboardFeatureProps, ItineraryDay } from "@/types";

export default function ItineraryPlanner({
  room,
  user,
  onLocationChange,
}: DashboardFeatureProps) {
  const [destination, setDestination] = useState(room.destination || "");
  const [days, setDays] = useState(room.days || 3);
  const [travelers, setTravelers] = useState(1);
  const [itinerary, setItinerary] = useState<ItineraryDay[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const generateItinerary = async () => {
    if (!destination) return;
    setLoading(true);
    setError("");
    onLocationChange(destination);

    try {
      const res = await fetch("/api/ai/itinerary", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ destination, days, travelers }),
      });
      const data = await res.json();
      if (data.error) throw new Error(data.error);
      setItinerary(data.itinerary || []);
    } catch (err: any) {
      setError(err.message || "Failed to generate itinerary");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-2xl font-bold text-gray-900">
          Itinerary Planner
        </h2>
        <p className="text-gray-500 mt-1">
          Generate an AI-powered travel itinerary
        </p>
      </div>

      {/* Form */}
      <div className="bg-white rounded-xl border p-6 space-y-4">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">
            Destination
          </label>
          <div className="relative">
            <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input
              type="text"
              value={destination}
              onChange={(e) => setDestination(e.target.value)}
              placeholder="Where are you going?"
              className="w-full pl-10 pr-4 py-2.5 border rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none"
            />
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Days
            </label>
            <div className="relative">
              <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
              <input
                type="number"
                value={days}
                onChange={(e) => setDays(parseInt(e.target.value) || 1)}
                min={1}
                max={30}
                className="w-full pl-10 pr-4 py-2.5 border rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none"
              />
            </div>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Travelers
            </label>
            <div className="relative">
              <Users className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
              <input
                type="number"
                value={travelers}
                onChange={(e) => setTravelers(parseInt(e.target.value) || 1)}
                min={1}
                max={20}
                className="w-full pl-10 pr-4 py-2.5 border rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none"
              />
            </div>
          </div>
        </div>

        <button
          onClick={generateItinerary}
          disabled={!destination || loading}
          className="w-full py-2.5 bg-teal-600 hover:bg-teal-700 disabled:bg-gray-300 text-white font-medium rounded-lg flex items-center justify-center gap-2 transition-colors"
        >
          {loading ? (
            <>
              <Loader2 className="w-4 h-4 animate-spin" /> Generating...
            </>
          ) : (
            <>
              <Sparkles className="w-4 h-4" /> Generate Itinerary
            </>
          )}
        </button>
      </div>

      {error && (
        <div className="bg-red-50 border border-red-200 text-red-700 rounded-lg p-4 text-sm">
          {error}
        </div>
      )}

      {/* Itinerary display */}
      {itinerary.length > 0 && (
        <div className="space-y-4">
          {itinerary.map((day) => (
            <div
              key={day.day}
              className="bg-white rounded-xl border overflow-hidden"
            >
              <div className="bg-teal-50 px-6 py-3 border-b">
                <h3 className="font-semibold text-teal-900">
                  Day {day.day}: {day.title}
                </h3>
              </div>
              <div className="p-6 space-y-4">
                {day.activities?.map((activity, i) => (
                  <div key={i} className="flex gap-4">
                    <div className="flex flex-col items-center">
                      <div className="w-8 h-8 rounded-full bg-teal-100 flex items-center justify-center">
                        <Clock className="w-4 h-4 text-teal-600" />
                      </div>
                      {i < (day.activities?.length || 0) - 1 && (
                        <div className="w-px flex-1 bg-gray-200 mt-1" />
                      )}
                    </div>
                    <div className="flex-1 pb-4">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-xs font-medium text-teal-600 bg-teal-50 px-2 py-0.5 rounded-full">
                          {activity.time}
                        </span>
                        <span className="text-xs text-gray-400 capitalize">
                          {activity.type}
                        </span>
                      </div>
                      <h4 className="font-medium text-gray-900">
                        {activity.title}
                      </h4>
                      <p className="text-sm text-gray-500 mt-0.5">
                        {activity.description}
                      </p>
                      {activity.location && (
                        <p className="text-xs text-gray-400 mt-1 flex items-center gap-1">
                          <MapPin className="w-3 h-3" /> {activity.location}
                        </p>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { Compass, Menu, X } from "lucide-react";
import AuthModal from "@/app/components/auth/AuthModal";
import { createClient } from "@/lib/supabase/client";
import type { User } from "@supabase/supabase-js";

export default function LandingNav() {
  const [scrolled, setScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [authModalOpen, setAuthModalOpen] = useState(false);
  const [authView, setAuthView] = useState<"signin" | "signup">("signin");
  const [user, setUser] = useState<User | null>(null);
  const supabase = createClient();

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  useEffect(() => {
    supabase.auth.getUser().then(({ data }) => setUser(data.user));
    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_, session) => {
      setUser(session?.user ?? null);
    });
    return () => subscription.unsubscribe();
  }, []);

  const handleSignOut = async () => {
    await supabase.auth.signOut();
    setUser(null);
  };

  return (
    <>
      <nav
        className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
          scrolled
            ? "bg-white/90 backdrop-blur-md shadow-sm"
            : "bg-transparent"
        }`}
      >
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">
            {/* Logo */}
            <Link href="/" className="flex items-center gap-2">
              <Compass
                className={`w-6 h-6 ${
                  scrolled ? "text-teal-600" : "text-white"
                }`}
              />
              <span
                className={`text-xl font-bold ${
                  scrolled ? "text-gray-900" : "text-white"
                }`}
              >
                Tripp
              </span>
            </Link>

            {/* Desktop links */}
            <div className="hidden md:flex items-center gap-8">
              <a
                href="#features"
                className={`text-sm font-medium transition-colors ${
                  scrolled
                    ? "text-gray-600 hover:text-gray-900"
                    : "text-white/80 hover:text-white"
                }`}
              >
                Features
              </a>
              <a
                href="#testimonials"
                className={`text-sm font-medium transition-colors ${
                  scrolled
                    ? "text-gray-600 hover:text-gray-900"
                    : "text-white/80 hover:text-white"
                }`}
              >
                Testimonials
              </a>
              <Link
                href="/room"
                className={`text-sm font-medium transition-colors ${
                  scrolled
                    ? "text-gray-600 hover:text-gray-900"
                    : "text-white/80 hover:text-white"
                }`}
              >
                Plan Trip
              </Link>
            </div>

            {/* Auth buttons */}
            <div className="hidden md:flex items-center gap-3">
              {user ? (
                <>
                  <Link
                    href="/room"
                    className="px-4 py-2 text-sm font-medium text-white bg-teal-500 rounded-full hover:bg-teal-600 transition-colors"
                  >
                    Dashboard
                  </Link>
                  <button
                    onClick={handleSignOut}
                    className={`text-sm font-medium ${
                      scrolled ? "text-gray-600" : "text-white/80"
                    }`}
                  >
                    Sign Out
                  </button>
                </>
              ) : (
                <>
                  <button
                    onClick={() => {
                      setAuthView("signin");
                      setAuthModalOpen(true);
                    }}
                    className={`text-sm font-medium ${
                      scrolled
                        ? "text-gray-600 hover:text-gray-900"
                        : "text-white/80 hover:text-white"
                    }`}
                  >
                    Sign In
                  </button>
                  <button
                    onClick={() => {
                      setAuthView("signup");
                      setAuthModalOpen(true);
                    }}
                    className="px-4 py-2 text-sm font-medium text-white bg-teal-500 rounded-full hover:bg-teal-600 transition-colors"
                  >
                    Sign Up
                  </button>
                </>
              )}
            </div>

            {/* Mobile menu button */}
            <button
              className="md:hidden"
              onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
            >
              {mobileMenuOpen ? (
                <X
                  className={`w-6 h-6 ${
                    scrolled ? "text-gray-900" : "text-white"
                  }`}
                />
              ) : (
                <Menu
                  className={`w-6 h-6 ${
                    scrolled ? "text-gray-900" : "text-white"
                  }`}
                />
              )}
            </button>
          </div>
        </div>

        {/* Mobile menu */}
        {mobileMenuOpen && (
          <div className="md:hidden bg-white shadow-lg">
            <div className="px-4 py-4 space-y-3">
              <a
                href="#features"
                className="block text-gray-600 font-medium"
                onClick={() => setMobileMenuOpen(false)}
              >
                Features
              </a>
              <a
                href="#testimonials"
                className="block text-gray-600 font-medium"
                onClick={() => setMobileMenuOpen(false)}
              >
                Testimonials
              </a>
              <Link
                href="/room"
                className="block text-gray-600 font-medium"
                onClick={() => setMobileMenuOpen(false)}
              >
                Plan Trip
              </Link>
              <hr />
              {user ? (
                <button
                  onClick={handleSignOut}
                  className="block text-gray-600 font-medium"
                >
                  Sign Out
                </button>
              ) : (
                <>
                  <button
                    onClick={() => {
                      setAuthView("signin");
                      setAuthModalOpen(true);
                      setMobileMenuOpen(false);
                    }}
                    className="block text-gray-600 font-medium"
                  >
                    Sign In
                  </button>
                  <button
                    onClick={() => {
                      setAuthView("signup");
                      setAuthModalOpen(true);
                      setMobileMenuOpen(false);
                    }}
                    className="block w-full text-center py-2 bg-teal-500 text-white rounded-lg font-medium"
                  >
                    Sign Up
                  </button>
                </>
              )}
            </div>
          </div>
        )}
      </nav>

      <AuthModal
        isOpen={authModalOpen}
        onClose={() => setAuthModalOpen(false)}
        initialView={authView}
      />
    </>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import {
  Compass,
  MapPin,
  Calendar,
  Users,
  Plus,
  ArrowRight,
  Loader2,
  LogIn,
} from "lucide-react";
import { createClient } from "@/lib/supabase/client";
import AuthModal from "@/app/components/auth/AuthModal";
import Link from "next/link";

function generateCode(): string {
  const chars = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
  return Array.from(
    { length: 6 },
    () => chars[Math.floor(Math.random() * chars.length)]
  ).join("");
}

export default function RoomForm() {
  const [destination, setDestination] = useState("");
  const [days, setDays] = useState(3);
  const [members, setMembers] = useState(4);
  const [joinCode, setJoinCode] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [user, setUser] = useState<any>(null);
  const [authModalOpen, setAuthModalOpen] = useState(false);
  const router = useRouter();
  const searchParams = useSearchParams();
  const supabase = createClient();

  useEffect(() => {
    supabase.auth.getUser().then(({ data }) => setUser(data.user));
    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_, session) => {
      setUser(session?.user ?? null);
    });

    if (searchParams.get("signin") === "true") setAuthModalOpen(true);
    if (searchParams.get("error") === "not_found")
      setError("Room not found. Check the code and try again.");

    return () => subscription.unsubscribe();
  }, []);

  const createRoom = async () => {
    if (!user) {
      setAuthModalOpen(true);
      return;
    }
    if (!destination.trim()) {
      setError("Enter a destination");
      return;
    }
    setLoading(true);
    setError("");

    try {
      const code = generateCode();
      const { data: room, error: dbError } = await supabase
        .from("rooms")
        .insert({
          code,
          destination: destination.trim(),
          days,
          max_members: members,
          created_by: user.id,
        })
        .select()
        .single();

      if (dbError) throw dbError;

      await supabase.from("room_members").insert({
        room_id: room.id,
        user_id: user.id,
        role: "owner",
      });

      router.push(`/room/${code}`);
    } catch (err: any) {
      setError(err.message || "Failed to create room");
    } finally {
      setLoading(false);
    }
  };

  const joinRoom = async () => {
    if (!user) {
      setAuthModalOpen(true);
      return;
    }
    if (joinCode.length !== 6) {
      setError("Enter a valid 6-character code");
      return;
    }
    setLoading(true);
    setError("");

    try {
      const { data: room } = await supabase
        .from("rooms")
        .select("id, code")
        .eq("code", joinCode.toUpperCase())
        .single();

      if (!room) {
        setError("Room not found");
        setLoading(false);
        return;
      }
      router.push(`/room/${room.code}`);
    } catch (err: any) {
      setError(err.message || "Failed to join room");
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <div className="w-full max-w-4xl">
        {/* Header */}
        <div className="text-center mb-8">
          <Link href="/" className="inline-flex items-center gap-2 mb-6">
            <Compass className="w-8 h-8 text-teal-600" />
            <span className="text-2xl font-bold text-gray-900">Tripp</span>
          </Link>
          <h1 className="text-3xl font-bold text-gray-900 mb-2">
            Plan Your Next Adventure
          </h1>
          <p className="text-gray-500">
            Create a room to plan together, or join an existing one
          </p>
          {!user && (
            <button
              onClick={() => setAuthModalOpen(true)}
              className="mt-3 inline-flex items-center gap-2 text-sm text-teal-600 hover:text-teal-700 font-medium"
            >
              <LogIn className="w-4 h-4" />
              Sign in to get started
            </button>
          )}
        </div>

        {error && (
          <div className="bg-red-50 border border-red-200 text-red-700 rounded-lg p-3 text-sm mb-6 text-center">
            {error}
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Create room */}
          <div className="bg-white rounded-2xl border shadow-sm p-8">
            <div className="flex items-center gap-3 mb-6">
              <div className="w-10 h-10 rounded-xl bg-teal-100 flex items-center justify-center">
                <Plus className="w-5 h-5 text-teal-600" />
              </div>
              <div>
                <h2 className="text-lg font-semibold text-gray-900">
                  Create New Room
                </h2>
                <p className="text-xs text-gray-500">
                  Start a trip planning room
                </p>
              </div>
            </div>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Destination
                </label>
                <div className="relative">
                  <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                  <input
                    type="text"
                    value={destination}
                    onChange={(e) => setDestination(e.target.value)}
                    placeholder="Where are you going?"
                    className="w-full pl-10 pr-4 py-2.5 border rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none"
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Days
                  </label>
                  <div className="relative">
                    <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                    <input
                      type="number"
                      value={days}
                      onChange={(e) => setDays(parseInt(e.target.value) || 1)}
                      min={1}
                      max={30}
                      className="w-full pl-10 pr-4 py-2.5 border rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none"
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Max Members
                  </label>
                  <div className="relative">
                    <Users className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                    <input
                      type="number"
                      value={members}
                      onChange={(e) =>
                        setMembers(parseInt(e.target.value) || 2)
                      }
                      min={2}
                      max={20}
                      className="w-full pl-10 pr-4 py-2.5 border rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none"
                    />
                  </div>
                </div>
              </div>

              <button
                onClick={createRoom}
                disabled={loading}
                className="w-full py-2.5 bg-teal-600 hover:bg-teal-700 disabled:bg-gray-300 text-white font-medium rounded-lg flex items-center justify-center gap-2 transition-colors"
              >
                {loading ? (
                  <Loader2 className="w-4 h-4 animate-spin" />
                ) : (
                  <Plus className="w-4 h-4" />
                )}
                Create Room
              </button>
            </div>
          </div>

          {/* Join room */}
          <div className="bg-white rounded-2xl border shadow-sm p-8">
            <div className="flex items-center gap-3 mb-6">
              <div className="w-10 h-10 rounded-xl bg-blue-100 flex items-center justify-center">
                <ArrowRight className="w-5 h-5 text-blue-600" />
              </div>
              <div>
                <h2 className="text-lg font-semibold text-gray-900">
                  Join Existing Room
                </h2>
                <p className="text-xs text-gray-500">
                  Enter a room code to join
                </p>
              </div>
            </div>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Room Code
                </label>
                <input
                  type="text"
                  value={joinCode}
                  onChange={(e) =>
                    setJoinCode(e.target.value.toUpperCase().slice(0, 6))
                  }
                  placeholder="XXXXXX"
                  className="w-full px-4 py-2.5 border rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none text-center text-2xl font-mono tracking-[0.5em] uppercase"
                  maxLength={6}
                />
              </div>

              <button
                onClick={joinRoom}
                disabled={joinCode.length !== 6 || loading}
                className="w-full py-2.5 bg-blue-600 hover:bg-blue-700 disabled:bg-gray-300 text-white font-medium rounded-lg flex items-center justify-center gap-2 transition-colors"
              >
                {loading ? (
                  <Loader2 className="w-4 h-4 animate-spin" />
                ) : (
                  <ArrowRight className="w-4 h-4" />
                )}
                Join Room
              </button>

              <p className="text-xs text-center text-gray-400">
                Ask the room creator for the 6-character code
              </p>
            </div>
          </div>
        </div>
      </div>

      <AuthModal
        isOpen={authModalOpen}
        onClose={() => setAuthModalOpen(false)}
        initialView="signin"
      />
    </>
  );
}
